import { BrowserRouter, Routes, Route } from "react-router-dom";
import Navbar from "./components/Navbar";
import ProtectedRoute from "./components/ProtectedRoute";
import Home from "./pages/Home";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Dashboard from "./pages/Dashboard";
import Courses from "./pages/Courses";
import AddCourse from "./pages/AddCourse";
import Enrollments from "./pages/Enrollments";
import Admin from "./pages/Admin";
import AdminPanel from "./pages/AdminPanel";
import EditCourse from "./pages/EditCourse";
import CourseReviews from "./pages/CourseReviews";
import Reports from "./pages/Reports";
import AddTest from "./pages/AddTest";
import Banned from "./pages/Banned";
import TeacherCourses from "./pages/TeacherCourses";
import Announcements from "./pages/Announcements";

function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/banned" element={<Banned />} />
        <Route path="/course-reviews" element={<ProtectedRoute allowedRoles={["teacher"]}><CourseReviews /></ProtectedRoute>} />
        <Route
          path="/dashboard"
          element={<ProtectedRoute><Dashboard /></ProtectedRoute>}
        />
        <Route
          path="/courses"
          element={<ProtectedRoute><Courses /></ProtectedRoute>}
        />
        <Route
          path="/add-course"
          element={<ProtectedRoute allowedRoles={["teacher"]}><AddCourse /></ProtectedRoute>}
        />
        <Route
          path="/add-test"
          element={<ProtectedRoute allowedRoles={["teacher"]}><AddTest /></ProtectedRoute>}
        />
        <Route
          path="/enrollments"
          element={<ProtectedRoute allowedRoles={["student"]}><Enrollments /></ProtectedRoute>}
        />
        <Route
          path="/admin"
          element={<ProtectedRoute allowedRoles={["admin"]}><Admin /></ProtectedRoute>}
        />
        <Route
          path="/schedules"
          element={<ProtectedRoute allowedRoles={["admin"]}><Schedules /></ProtectedRoute>}
        />
        <Route
          path="/reports"
          element={<ProtectedRoute allowedRoles={["admin"]}><Reports /></ProtectedRoute>}
        />
        <Route
          path="/edit-course/:id"
          element={<ProtectedRoute allowedRoles={["teacher"]}><EditCourse /></ProtectedRoute>}
        />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
